import { useState, useRef } from "react";

const LOGO_B64 = "";
const LOGO_SRC = `data:image/png;base64,${LOGO_B64}`;

const MONTHS = ["January","February","March","April","May","June","July","August","September","October","November","December"];
const CLASS_TYPES = [
  "Baby Ballet",
  "Ballet Tots",
  "Kinder",
  "Pre-Primary",
  "Primary",
  "Level 1",
  "Level 2",
  "Teens and Advance",
];
const DAYS_OF_WEEK = ["Mon","Tue","Wed","Thu","Fri","Sat","Sun"];

function generateDates(month, year, selectedDays) {
  const dates = [];
  const daysMap = { Mon:1,Tue:2,Wed:3,Thu:4,Fri:5,Sat:6,Sun:0 };
  const daysInMonth = new Date(year, month+1, 0).getDate();
  for (let d=1; d<=daysInMonth; d++) {
    const date = new Date(year, month, d);
    const dayName = Object.keys(daysMap).find(k => daysMap[k]===date.getDay());
    if (selectedDays.includes(dayName)) dates.push(new Date(year, month, d));
  }
  return dates;
}

function fmtShort(date) {
  return date.toLocaleDateString("en-PH",{month:"short",day:"numeric"});
}
function fmtFull(date) {
  return date.toLocaleDateString("en-PH",{day:"2-digit",month:"2-digit",year:"numeric"});
}



// Reusable Rate & Dates card for each class type
function RateDateCard({ title, emoji, showClassSelector, classLabel, setClassLabel, rate, setRate,
  classDays, toggleDay, useAutoDate, setUseAutoDate, generatedDates,
  customDates, setCustomDates, month, year, total, pink, gray, lbl, inp }) {

  const [manualDate, setManualDate] = useState("");

  const addManual = () => {
    if (!manualDate) return;
    const d = new Date(manualDate + "T12:00:00");
    if (!customDates.find(x => x.toDateString() === d.toDateString())) {
      setCustomDates(prev => [...prev, d]);
    }
    setManualDate("");
  };

  const removeDate = (date) => {
    setCustomDates(prev => prev.filter(d => d.toDateString() !== date.toDateString()));
  };

  const allCardDates = [...generatedDates, ...customDates].sort((a,b)=>a-b);
  const DAYS = ["Mon","Tue","Wed","Thu","Fri","Sat","Sun"];

  return (
    <div style={{background:"white",borderRadius:16,padding:20,boxShadow:"0 4px 20px rgba(244,167,185,0.12)",borderLeft:"4px solid #FADADD",display:"flex",flexDirection:"column",gap:14}}>
      {/* Header */}
      <div>
        <div style={{fontSize:13,fontWeight:700,color:gray,letterSpacing:"0.08em",textTransform:"uppercase",marginBottom:4}}>
          {emoji} {showClassSelector ? "" : title}
        </div>
        {showClassSelector && (
          <select value={classLabel} onChange={e=>setClassLabel(e.target.value)}
            style={{...inp,fontSize:13,fontWeight:700,color:gray,cursor:"pointer",paddingBottom:4}}>
            {["Baby Ballet","Ballet Tots","Kinder","Pre-Primary","Primary","Level 1","Level 2","Teens and Advance"].map(c=><option key={c} value={c}>{c}</option>)}
          </select>
        )}
      </div>

      {/* Rate */}
      <div>
        <label style={{...lbl,marginBottom:4}}>Rate per class (PHP)</label>
        <input type="number" value={rate} onChange={e=>setRate(Number(e.target.value))}
          style={{...inp,fontSize:14,fontWeight:600,color:pink}}/>
      </div>

      {/* Auto day-of-week selector (only for main class) */}
      {showClassSelector && (
        <div>
          <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:8}}>
            <span style={{fontSize:11,color:"#aaa"}}>Auto-fill by day of week</span>
            <div onClick={()=>setUseAutoDate(!useAutoDate)} style={{width:36,height:20,borderRadius:10,background:useAutoDate?pink:"#ddd",cursor:"pointer",position:"relative",transition:"all 0.2s",flexShrink:0}}>
              <div style={{width:14,height:14,borderRadius:"50%",background:"white",position:"absolute",top:3,left:useAutoDate?19:3,transition:"all 0.2s"}}/>
            </div>
          </div>
          {useAutoDate && (
            <div style={{display:"flex",flexWrap:"wrap",gap:4,marginBottom:6}}>
              {DAYS.map(day=>(
                <button key={day} onClick={()=>toggleDay(day)} style={{padding:"3px 8px",border:"1px solid",borderColor:classDays.includes(day)?pink:"#FADADD",background:classDays.includes(day)?pink:"transparent",color:classDays.includes(day)?"white":"#595959",fontSize:10,borderRadius:14,cursor:"pointer",transition:"all 0.15s"}}>
                  {day}
                </button>
              ))}
            </div>
          )}
          {generatedDates.length>0 && (
            <div style={{fontSize:10,color:pink,marginBottom:4}}>→ {generatedDates.length} dates auto-filled</div>
          )}
        </div>
      )}

      {/* Calendar */}
      <CalendarGrid
        month={month} year={year}
        generatedDates={generatedDates}
        customDates={customDates}
        setCustomDates={setCustomDates}
        pink={pink}
      />

      {/* Session count + total */}
      <div style={{background:"#FFF8F9",borderRadius:10,padding:"8px 12px",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
        <span style={{fontSize:11,color:"#aaa"}}>{allCardDates.length} session{allCardDates.length!==1?"s":""}</span>
        <span style={{fontSize:13,fontWeight:700,color:pink}}>₱{total.toLocaleString()}</span>
      </div>
    </div>
  );
}

// Interactive calendar component - click dates to add/remove them
function CalendarGrid({ month, year, generatedDates, customDates, setCustomDates, pink }) {
  const daysInMonth = new Date(year, month + 1, 0).getDate();
  const firstDay = new Date(year, month, 1).getDay(); // 0=Sun
  const lightPink = "#FADADD";
  const cream = "#FFF8F9";

  const isGenerated = (day) => {
    const d = new Date(year, month, day);
    return generatedDates.some(x => x.toDateString() === d.toDateString());
  };

  const isCustomAdded = (day) => {
    const d = new Date(year, month, day);
    return customDates.some(x => x.toDateString() === d.toDateString());
  };

  const isCustomRemoved = (day) => {
    // A generated date that was manually removed
    return false; // tracked via removedDates below - we'll handle via toggleDate
  };

  const toggleDate = (day) => {
    const d = new Date(year, month, day);
    const dStr = d.toDateString();
    const inGenerated = generatedDates.some(x => x.toDateString() === dStr);
    const inCustom = customDates.some(x => x.toDateString() === dStr);

    if (inCustom) {
      // Remove from custom
      setCustomDates(prev => prev.filter(x => x.toDateString() !== dStr));
    } else if (!inGenerated) {
      // Add to custom
      setCustomDates(prev => [...prev, d]);
    }
    // If it's a generated date and not in custom, it's already shown - do nothing
    // (generated dates are controlled by day-of-week selector)
  };

  const isActive = (day) => isGenerated(day) || isCustomAdded(day);

  const DAY_LABELS = ["Su","Mo","Tu","We","Th","Fr","Sa"];

  const cells = [];
  // Empty cells before first day
  for (let i = 0; i < firstDay; i++) cells.push(null);
  // Day cells
  for (let d = 1; d <= daysInMonth; d++) cells.push(d);

  return (
    <div style={{marginTop:12}}>
      <div style={{fontSize:11,color:"#aaa",marginBottom:8,letterSpacing:"0.05em"}}>
        Click dates to add · Click again to remove
      </div>
      {/* Day headers */}
      <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",gap:3,marginBottom:3}}>
        {DAY_LABELS.map(d => (
          <div key={d} style={{textAlign:"center",fontSize:9,fontWeight:700,color:"#aaa",letterSpacing:"0.05em",padding:"2px 0"}}>{d}</div>
        ))}
      </div>
      {/* Date cells */}
      <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",gap:3}}>
        {cells.map((day, i) => {
          if (!day) return <div key={`e-${i}`}/>;
          const active = isActive(day);
          const generated = isGenerated(day);
          const custom = isCustomAdded(day);
          return (
            <div
              key={day}
              onClick={() => toggleDate(day)}
              style={{
                textAlign:"center",
                padding:"5px 2px",
                borderRadius:8,
                fontSize:11,
                fontWeight: active ? 700 : 400,
                cursor:"pointer",
                background: active ? pink : cream,
                color: active ? "white" : "#595959",
                border: custom ? `2px solid ${pink}` : generated ? `2px solid ${pink}` : "2px solid transparent",
                opacity: 1,
                transition:"all 0.15s",
                userSelect:"none",
              }}
              title={generated ? "Auto-generated (click recurring days to remove)" : custom ? "Manually added (click to remove)" : "Click to add"}
            >
              {day}
            </div>
          );
        })}
      </div>
      {/* Legend */}
      <div style={{display:"flex",gap:12,marginTop:10,flexWrap:"wrap"}}>
        <div style={{display:"flex",alignItems:"center",gap:4,fontSize:10,color:"#aaa"}}>
          <div style={{width:10,height:10,borderRadius:3,background:pink}}/> Class date
        </div>
        <div style={{display:"flex",alignItems:"center",gap:4,fontSize:10,color:"#aaa"}}>
          <div style={{width:10,height:10,borderRadius:3,background:cream,border:`1px solid #ddd`}}/> No class
        </div>
      </div>
    </div>
  );
}

